import anthropic
import json
from dataclasses import dataclass, field
from typing import Any

@dataclass
class EvidenceStore:
    items: list[dict] = field(default_factory=list)

    def add(self, source: str, passage: str, relevance: float):
        self.items.append({"source": source, "passage": passage, "relevance": relevance})

    def to_context(self, max_items: int = 40) -> str:
        sorted_items = sorted(self.items, key=lambda x: x["relevance"], reverse=True)
        lines = []
        for i, item in enumerate(sorted_items[:max_items]):
            lines.append(f"[{i+1}] ({item['source']}) {item['passage']}")
        return "
".join(lines)

def deep_research_agent(
    objective: str,
    search_tools: list,
    max_iterations: int = 8,
) -> dict[str, Any]:
    client = anthropic.Anthropic()
    evidence = EvidenceStore()
    iteration = 0

    # Step 1: Generate initial research plan
    plan_response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": f"""Create a research plan for the following objective.
Return JSON with:
- sub_questions: list of 4-6 specific questions to answer
- initial_queries: list of 4-6 search queries

Objective: {objective}"""
        }]
    )
    plan_text = plan_response.content[0].text
    # parse plan_text as JSON (simplified)
    plan = json.loads(plan_text[plan_text.find("{"):plan_text.rfind("}")+1])

    queries = plan.get("initial_queries", [objective])

    while iteration < max_iterations:
        iteration += 1

        # Step 2: Execute searches
        for query in queries[:4]:  # limit concurrent searches
            for tool in search_tools:
                results = tool(query)
                for result in results[:5]:
                    evidence.add(
                        source=result.get("url", "unknown"),
                        passage=result.get("snippet", ""),
                        relevance=result.get("score", 0.5)
                    )

        # Step 3: Detect gaps and plan next queries
        gap_response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            messages=[{
                "role": "user",
                "content": f"""Research objective: {objective}

Sub-questions: {json.dumps(plan.get("sub_questions", []))}

Current evidence:
{evidence.to_context(max_items=20)}

Identify any gaps. Return JSON:
{{"gaps_found": true/false, "next_queries": ["q1", "q2"], "confidence": 0-1}}"""
            }]
        )
        gap_text = gap_response.content[0].text
        gap_info = json.loads(gap_text[gap_text.find("{"):gap_text.rfind("}")+1])

        if not gap_info.get("gaps_found") or gap_info.get("confidence", 0) > 0.85:
            break

        queries = gap_info.get("next_queries", [])

    # Step 4: Synthesise final report
    synthesis_response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=4096,
        messages=[{
            "role": "user",
            "content": f"""Write a comprehensive research report on: {objective}

Evidence (cite by number):
{evidence.to_context(max_items=30)}

Requirements:
- Use inline citations like [1], [2]
- Structure with clear sections
- Synthesise across sources
- Note contradictions or uncertainty"""
        }]
    )

    return {
        "report": synthesis_response.content[0].text,
        "evidence_count": len(evidence.items),
        "iterations": iteration,
    }

import os
import anthropic
from tavily import TavilyClient

def build_research_tools():
    tavily = TavilyClient(api_key=os.environ["TAVILY_API_KEY"])

    def web_search(query: str) -> list[dict]:
        response = tavily.search(
            query=query,
            search_depth="advanced",
            max_results=5,
            include_raw_content=False,
        )
        return [
            {
                "url": r["url"],
                "snippet": r.get("content", r.get("snippet", "")),
                "score": r.get("score", 0.5),
            }
            for r in response.get("results", [])
        ]

    def academic_search(query: str) -> list[dict]:
        # Semantic Scholar API (free, no key required for basic use)
        import httpx
        resp = httpx.get(
            "https://api.semanticscholar.org/graph/v1/paper/search",
            params={
                "query": query,
                "fields": "title,abstract,year,authors,externalIds",
                "limit": 5,
            },
            timeout=15,
        )
        papers = resp.json().get("data", [])
        return [
            {
                "url": f"https://www.semanticscholar.org/paper/{p['paperId']}",
                "snippet": (p.get("abstract") or "")[:500],
                "score": 0.9 if p.get("year", 0) >= 2022 else 0.6,
            }
            for p in papers
        ]

    return [web_search, academic_search]

# Run research
tools = build_research_tools()
result = deep_research_agent(
    objective="How do transformer-based protein structure prediction models compare to AlphaFold2?",
    search_tools=tools,
    max_iterations=6,
)

print(result["report"])
